class ASTNode:
    def __init__(self, type, value=None, op=None, left=None, right=None, operand=None):
        self.type = type
        self.value = value
        self.op = op
        self.left = left
        self.right = right
        self.operand = operand


def parse(expression):
    if not expression or not expression.strip():
        raise ValueError("Empty expression")

    # Remove whitespace
    expression = expression.replace(" ", "")

    # Tokenizer
    tokens = []
    i = 0
    while i < len(expression):
        if expression[i].isdigit() or expression[i] == ".":
            # Parse number
            start = i
            while i < len(expression) and (
                expression[i].isdigit() or expression[i] == "."
            ):
                i += 1
            tokens.append(("NUMBER", expression[start:i]))
        elif expression[i] in "+-*/()":
            tokens.append(("OPERATOR", expression[i]))
            i += 1
        else:
            raise ValueError(f"Invalid token: {expression[i]}")

    # Parser using recursive descent
    def parse_expression():
        return parse_add_sub()

    def parse_add_sub():
        node = parse_mul_div()

        while tokens and tokens[0][0] == "OPERATOR" and tokens[0][1] in ["+", "-"]:
            op = tokens.pop(0)[1]
            right = parse_mul_div()
            node = ASTNode("binop", op=op, left=node, right=right)

        return node

    def parse_mul_div():
        node = parse_unary()

        while tokens and tokens[0][0] == "OPERATOR" and tokens[0][1] in ["*", "/"]:
            op = tokens.pop(0)[1]
            right = parse_unary()
            node = ASTNode("binop", op=op, left=node, right=right)

        return node

    def parse_unary():
        if tokens and tokens[0][0] == "OPERATOR" and tokens[0][1] == "-":
            tokens.pop(0)
            operand = parse_unary()
            return ASTNode("unary", op="-", operand=operand)
        else:
            return parse_primary()

    def parse_primary():
        if not tokens:
            raise ValueError("Unexpected end of expression")

        token_type, token_value = tokens[0]

        if token_type == "NUMBER":
            tokens.pop(0)
            return ASTNode("number", value=float(token_value))
        elif token_type == "OPERATOR" and token_value == "(":
            tokens.pop(0)  # consume '('
            node = parse_expression()
            if not tokens or tokens[0][0] != "OPERATOR" or tokens[0][1] != ")":
                raise ValueError("Unmatched parenthesis")
            tokens.pop(0)  # consume ')'
            return node
        else:
            raise ValueError(f"Unexpected token: {token_value}")

    # Parse the expression
    result = parse_expression()

    # Check if there are remaining tokens
    if tokens:
        raise ValueError("Invalid expression")

    return result


def evaluate(node):
    if node.type == "number":
        return node.value
    elif node.type == "binop":
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)
        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
    elif node.type == "unary":
        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val
    else:
        raise ValueError(f"Unknown node type: {node.type}")
